    if (gcpm != null) {
        gcExecutor = Executors.newScheduledThreadPool(1, new ThreadFactory() {

            @Override
            public Thread newThread(Runnable r) {
                return new Thread(r, "RevisionStore-GC");
            }
        });
        gcExecutor.scheduleWithFixedDelay(new Runnable() {

            @Override
            public void run() {
