public void process(Exchange exchange) throws Exception {
        Exchange resultExchange = exchange.copy();
        resultExchange.setPattern(ExchangePattern.InOut);
            resultExchange.getIn().removeHeader(Exchange.BEAN_METHOD_NAME);
        String ognlPath = "";
