                        if (neg && val == Long.MIN_VALUE) {
                if (length == 1 || bytes[startPos + 1] == delimiter) {
                    return Long.MIN_VALUE;
                } else {
                    throw new NumberFormatException("value overflow");
                }
            } else {
                throw new NumberFormatException("value overflow");
            }
        }
    }
    return neg ? -val : val;
