            if (PathUtils.isAbsolute(sub)) {
                return path + sub;
            } else {
                return PathUtils.concat(path, r.getPath());
            }
        }

        @Override
        public PropertyValue getValue(String columnName) {
            return r.getValue(columnName);
        }
    };
