@Nonnull
private synchronized TreeLocation getLocationOrNull() {
    if (location.exists() && sessionDelegate.getRevision() != revision) {
        location = sessionDelegate.getLocation(location.getPath());
        revision = sessionDelegate.getRevision();
    }
    return location;
