            String className;
                        if (componentClass.isPrimitive()) {
                className = encodePrimitiveClass(componentClass);
            } else             {
                className = "L" + componentClass.getName() + ";";
            }
            Class<OUT> classArray = null;
            try {
                classArray = (Class<OUT>) Class.forName("[" + className);
