                    value.setLength(0);
                    isKey = true;
                    isValue = false;
                    isRaw = false;
                                        i++;
                }
                continue;
            }
                        if (isKey && ch == '=') {
                isKey = false;
                isValue = true;
                isRaw = false;
                continue;
            }
                        if (ch == '&') {
                                addParameter(key.toString(), value.toString(), rc, useRaw || isRaw);
                key.setLength(0);
                value.setLength(0);
                isKey = true;
                isValue = false;
                isRaw = false;
                continue;
            }
                        if (isKey) {
                key.append(ch);
            } else if (isValue) {
                value.append(ch);
            }
