        final Option option = (Option) i.next();
                boolean validate = option.isRequired() || option instanceof Group;
        if (validate) {
            option.validate(commandLine);
        }
                if (commandLine.hasOption(option)) {
            if (++present > maximum) {
                unexpected = option;
