        }
    }
    if (paths == null) {
                throw new IllegalStateException("OrderedPropertyIndex index is used even when no index is available for filter " + filter);
    }
    Cursor cursor = Cursors.newPathCursor(paths, filter.getQueryEngineSettings());
    if (depth > 1) {
