                Renamer renamer = nameStack.peek();
                if (renamer.stripConstIfReplaced()) {
                                        n.removeProp(Node.IS_CONSTANT_NAME);
                }
                n.setString(newName);
                t.getCompiler().reportCodeChange();
            }
            break;
        case Token.FUNCTION:
                                    nameStack.pop();
            break;
        case Token.CATCH:
                        nameStack.pop();
            break;
    }
