                                                while (t.read() != ']') {
                                                }
                    } else {
                                                t.read();
                    }
                    break;
                }
            default:
                throw new IllegalArgumentException("jsonDiff: illegal token '" + t.getToken() + "' at pos: " + t.getLastPos() + ' ' + jsonDiff);
        }
    }
    return continueComparison;
