protected String getLanguage() {
    Node n = node;
    while (n != null) {
        if (n.getNodeType() == Node.ELEMENT_NODE) {
            Element e = (Element) n;
            String attr = e.getAttribute("xml:lang");
            if (attr != null && !attr.equals("")) {
                return attr;
            }
        }
        n = n.getParentNode();
    }
    return null;
