private static int compare(MapEntry before, MapEntry after) {
    if (before == null) {
                return 1;
    } else if (after == null) {
                return -1;
    } else {
        return ComparisonChain.start().compare(before.getHash(), after.getHash()).compare(before.getName(), after.getName()).result();
    }
