    if (explicitMethodName == null && processor != null) {
        LOG.trace("Using a custom adapter as bean invocation: {}", processor);
        try {
            processor.process(exchange);
        } catch (Throwable e) {
            exchange.setException(e);
        }
        callback.done(true);
        return true;
    }
