        if (((Component) children).getId().equals(child.getId())) {
            return 0;
        }
    } else {
        if (children != null) {
            final Component[] components = (Component[]) children;
            for (int i = 0; i < components.length; i++) {
                if (components[i].getId().equals(child.getId())) {
                    return i;
                }
            }
        }
    }
    return -1;
