        if (checkpointDuration < overallMinDuration) {
            overallMinDuration = checkpointDuration;
        }
        overallTotalDuration += checkpointDuration;
                if (overallStateSize < overallMinStateSize) {
            overallMinStateSize = overallStateSize;
        }
