public static double factorialLog(final int n) {
    if (n < 0) {
        throw new IllegalArgumentException("must have n > 0 for n!");
    }
    double logSum = 0;
    for (int i = 2; i <= n; i++) {
        logSum += Math.log((double) i);
    }
    return logSum;
