        RevisionRange range;
        for (int i = list.size() - 1; i >= 0; i--) {
            range = list.get(i);
            if (range.seenAt.compareRevisionTimeThenClusterId(seenAt) <= 0) {
                                                Long inactiveSince = inactive.get(range.revision.getClusterId());
