        int firstDigits = Integer.parseInt(creditCardNumber.substring(0, 5));
        if (firstDigits >= 622126 && firstDigits <= 622925) {
            return CreditCard.CHINA_UNIONPAY;
        }
    }
    return CreditCard.INVALID;
